SELECT id, bundle_id, wincc_variable_name, structure_type, data_type, display_label, floor_code, room_base, room_canonical, suite_suffix, metric_kind_code, cached_alarm_min_value, cached_alarm_max_value, cached_alarm_limits_at, alarm_override_min, alarm_override_max, enabled, sort_order, created_at FROM telemetry_watchlist_tag WHERE bundle_id = #{bundleId}
AND (wincc_variable_name LIKE CONCAT('%', #{q}, '%') OR display_label LIKE CONCAT('%', #{q}, '%') OR floor_code LIKE CONCAT('%', #{q}, '%') OR room_canonical LIKE CONCAT('%', #{q}, '%') OR metric_kind_code LIKE CONCAT('%', #{q}, '%') OR structure_type LIKE CONCAT('%', #{q}, '%') OR data_type LIKE CONCAT('%', #{q}, '%'))
ORDER BY sort_order ASC, id ASC LIMIT #{limit} OFFSET #{offset}

